tools.description:
Deploys an Edge Function to a Supabase project. If the function already exists, this will create a new version. Example:

import "jsr:@supabase/functions-js/edge-runtime.d.ts";

Deno.serve(async (req: Request) => {
  const data = {
    message: "Hello there!"
  };

  return new Response(JSON.stringify(data), {
    headers: {
      'Content-Type': 'application/json',
      'Connection': 'keep-alive'
    }
  });
});

output.arguments:
{"query":"with qualifying_accounts as (
  select distinct m.account_number
  from public.member m
  where exists (
    select 1 from public.share s where s.account_number = m.account_number
  )
    and exists (
    select 1 from public.card c where c.account_number = m.account_number
  )
    and not exists (
    select 1 from public.loan l where l.account_number = m.account_number
  )
)
select count(*) as qualifying_accounts,
       (select count(*) from public.member m join qualifying_accounts q using (account_number)) as member_rows
from qualifying_accounts;"}
